+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import type { RelationPair } from '../../relation/types';
+import type { World } from '../../world';
+import type { EventType, QueryInstance, TrackingGroup } from '../types';
+
+const pairKey = (pair: RelationPair) =>
+    `${pair[$internal].relation[$internal].trait.id}:${pair[$internal].target}`;
+
+function matchesPair(pair: RelationPair, event: RelationPair): boolean {
+    return (
+        pair[$internal].relation === event[$internal].relation &&
+        (pair[$internal].target === '*' || pair[$internal].target === event[$internal].target)
+    );
+}
+
+function pairsMatch(group: TrackingGroup, eid: number): boolean {
+    if (!group.pairs.length) return group.logic === 'and';
+    const events = group.pairTrackers.get(eid);
+    if (!events) return false;
+    const matches = (pair: RelationPair) => {
+        if (pair[$internal].target !== '*') return events.get(pairKey(pair)) === group.type;
+        const prefix = `${pair[$internal].relation[$internal].trait.id}:`;
+        for (const [key, type] of events) if (key.startsWith(prefix) && type === group.type) return true;
+        return false;
+    };
+    return group.logic === 'and' ? group.pairs.every(matches) : group.pairs.some(matches);
+}
+
+/** Record and evaluate a target-level relation event for tracking modifiers. */
+export function checkQueryPairTracking(
+    world: World,
+    query: QueryInstance,
+    entity: Entity,
+    eventType: EventType,
+    pair: RelationPair
+): boolean {
+    const eid = getEntityId(entity);
+    let affected = false;
+
+    for (const group of query.trackingGroups) {
+        if (!group.pairs.some((tracked) => matchesPair(tracked, pair))) continue;
+        affected = true;
+        let events = group.pairTrackers.get(eid);
+        if (!events) group.pairTrackers.set(eid, (events = new Map()));
+        const key = pairKey(pair);
+        const previous = events.get(key);
+        // Adds and removes of the same pair within one observation window cancel.
+        if ((previous === 'add' && eventType === 'remove') || (previous === 'remove' && eventType === 'add')) {
+            events.delete(key);
+        } else {
+            events.set(key, eventType);
+        }
+    }
+
+    if (!affected) return false;
+    // Run the regular checker with a zero bit so it verifies static and trait tracking
+    // constraints without introducing a synthetic trait event.
+    if (!checkStaticAndTraitTracking(world, query, entity)) return false;
+
+    let hasOr = false;
+    for (const group of query.trackingGroups) {
+        const pairMatches = pairsMatch(group, eid);
+        if (group.logic === 'and') {
+            if (group.pairs.length && !pairMatches) return false;
+        } else if (group.pairs.length) {
+            hasOr = true;
+            if (pairMatches) return true;
+        }
+    }
+    return !hasOr;
+}
+
+function checkStaticAndTraitTracking(world: World, query: QueryInstance, entity: Entity): boolean {
+    const eid = getEntityId(entity);
+    const masks = world[$internal].entityMasks;
+    for (let i = 0; i < query.generations.length; i++) {
+        const bitmask = query.staticBitmasks[i];
+        const mask = masks[query.generations[i]]?.[eid] ?? 0;
+        if ((bitmask.forbidden && (mask & bitmask.forbidden)) ||
+            (bitmask.required && (mask & bitmask.required) !== bitmask.required) ||
+            (bitmask.or && !(mask & bitmask.or))) return false;
+    }
+    for (const group of query.trackingGroups) {
+        if (group.logic !== 'and') continue;
+        for (let generation = 0; generation < group.bitmasks.length; generation++) {
+            const needed = group.bitmasks[generation];
+            if (!needed) continue;
+            if (((group.trackers[generation]?.[eid] ?? 0) & needed) !== needed) return false;
+        }
+    }
+    return true;
+}
