+/** Notify pair-aware tracking queries about a relation target event. */
+export function setPairTracking(
+    world: World,
+    entity: Entity,
+    pair: RelationPair,
+    eventType: 'add' | 'remove' | 'change'
+) {
+    const trait = pair[$internal].relation[$internal].trait;
+    const data = getTraitInstance(world[$internal].traitInstances, trait);
+    if (!data) return;
+    for (const query of data.trackingQueries) {
+        const match = query.checkPairTracking(world, entity, eventType, pair);
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
